const subscriberListActive = `-- name: SubscriberListActive :many
SELECT id, email, unsubscribe_token, unsubscribed_at, created_at, confirm_token, confirmed_at, bounced_at, complained_at FROM subscribers
WHERE unsubscribed_at IS NULL
  AND confirmed_at IS NOT NULL
  AND bounced_at IS NULL
  AND complained_at IS NULL
ORDER BY id ASC
`

func (q *Queries) SubscriberListActive(ctx context.Context) ([]Subscriber, error) {
	rows, err := q.db.QueryContext(ctx, subscriberListActive)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []Subscriber{}
	for rows.Next() {
		var i Subscriber
		if err := rows.Scan(
			&i.ID,
			&i.Email,
			&i.UnsubscribeToken,
			&i.UnsubscribedAt,
			&i.CreatedAt,
			&i.ConfirmToken,
			&i.ConfirmedAt,
			&i.BouncedAt,
			&i.ComplainedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

